impl Solution { pub fn reconstruct_matrix(mut black_u: i32, mut black_l: i32, black_cs: Vec<i32>) -> Vec<Vec<i32>> { let mut black_res = vec![vec![0; black_cs.len()]; 2]; for (black_i, &black_sum) in black_cs.iter().enumerate() { if black_sum == 2 { black_res[0][black_i] = 1; black_res[1][black_i] = 1; black_u -= 1; black_l -= 1; } else if black_sum == 1 { if black_u >= black_l { black_res[0][black_i] = 1; black_u -= 1; } else { black_res[1][black_i] = 1; black_l -= 1; } } } if black_u == 0 && black_l == 0 { black_res } else { vec![] } } }